import{createDesmosGraphs,desmosColors,desmosPointStyles}from"/scripts/src/desmos.min.js";import{raw}from"/scripts/src/main.min.js";export default function(){createDesmosGraphs({continuityExample:{bounds:{xmin:-6,xmax:6,ymin:-6,ymax:6},expressions:[{latex:raw`f(x) = \{x \leq -3: x, -3 \leq x \leq 3: \frac{1}{27} x^3, 3 \leq x: \frac{1}{(4 - x)^2}\}`,color:desmosColors.purple,hidden:!0,secret:!0},{latex:raw`f(x)`,color:desmosColors.purple},{latex:raw`(-3, -3), (0, 0)`,color:desmosColors.purple,pointStyle:desmosPointStyles.OPEN},{latex:raw`(-3, -1), (0, 1)`,color:desmosColors.purple}]},continuityLimit:{bounds:{xmin:-10,xmax:10,ymin:-10,ymax:10},expressions:[{latex:raw`\frac{\cos(x^2) - x}{2 - \tan(x)}`,color:desmosColors.purple}]},ivtExample:{bounds:{xmin:-1,xmax:4,ymin:-1,ymax:4},expressions:[{latex:raw`(1, 2), (3, 1)`,color:desmosColors.black},{latex:raw`f(x) = \frac{2}{x^{\frac{\ln(2)}{\ln(3)}}}`,color:desmosColors.purple},{latex:raw`g(x) = \frac{1}{2}\sin(\frac{\pi}{2}x) + \frac{3}{2}`,color:desmosColors.blue},{latex:raw`h(x) = \frac{3}{2}x^2 - \frac{13}{2}x + 7`,color:desmosColors.red}]},ivtExample2:{bounds:{xmin:-15,xmax:15,ymin:-15,ymax:15},expressions:[{latex:raw`f(x) = x - \cos(x)`,color:desmosColors.purple},{latex:raw`(0, f(0)), (\frac{\pi}{2}, f(\frac{\pi}{2}))`,color:desmosColors.blue}]}})}